import { MakeLogicType, connect, events, kea, key, path, props, selectors } from 'kea'
import { loaders } from 'kea-loaders'

import api from 'lib/api'
import { toParams } from 'lib/utils/url'
import { teamLogic } from 'scenes/teamLogic'

import { ActorType } from '~/types'

import type { PersonActorType } from '../../types'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface relatedGroupsLogicValues {
    currentTeamId: number | null // teamLogic
    relatedActors: ActorType[]
    relatedActorsLoading: boolean
    relatedPeople: PersonActorType[]
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface relatedGroupsLogicActions {
    loadRelatedActors: () => any
    loadRelatedActorsFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadRelatedActorsSuccess: (
        relatedActors: ActorType[],
        payload?: any
    ) => {
        relatedActors: ActorType[]
        payload?: any
    }
    setGroup: () => any
    setGroupFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    setGroupSuccess: (
        relatedActors: never[],
        payload?: any
    ) => {
        relatedActors: never[]
        payload?: any
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface relatedGroupsLogicProps {
    groupTypeIndex: number | null
    id: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface relatedGroupsLogicMeta {
    key: string
    __keaTypeGenInternalSelectorTypes: {
        relatedPeople: (relatedActors: ActorType[]) => PersonActorType[]
    }
}

export type relatedGroupsLogicType = MakeLogicType<
    relatedGroupsLogicValues,
    relatedGroupsLogicActions,
    relatedGroupsLogicProps,
    relatedGroupsLogicMeta
>

export const relatedGroupsLogic = kea<relatedGroupsLogicType>([
    props(
        {} as {
            groupTypeIndex: number | null
            id: string
        }
    ),
    key((props) => `${props.groupTypeIndex ?? 'person'}-${props.id}`),
    path(['scenes', 'groups', 'relatedGroupsLogic']),
    connect(() => ({ values: [teamLogic, ['currentTeamId']] })),
    loaders(({ values, props }) => ({
        relatedActors: [
            [] as ActorType[],
            {
                loadRelatedActors: async () => {
                    const url = `api/environments/${values.currentTeamId}/groups/related?${toParams({
                        group_type_index: props.groupTypeIndex,
                        id: props.id,
                    })}`
                    return await api.get(url)
                },
                setGroup: () => [],
            },
        ],
    })),
    selectors(({ selectors }) => ({
        relatedPeople: [
            () => [selectors.relatedActors],
            (relatedActors: ActorType[]) => relatedActors.filter((actor) => actor.type === 'person'),
        ],
    })),
    events(({ actions }) => ({
        afterMount: actions.loadRelatedActors,
    })),
])
